> **Note:**&#x20;
>
> Example Setup
>
> This example connects to an instance of MongoDB by using a
> connection URI. To learn more about connecting to your MongoDB
> instance, see the [Connect to MongoDB](node-connect) guide. This example
> also uses the `movies` collection in the `sample_mflix` database
> included in the [Atlas sample datasets](atlas/sample-data). You
> can load them into your database on the free tier of MongoDB Atlas by
> following the [MongoDB Get Started](get-started).The following full file example finds a single document from the `movies`
collection. It uses the following parameters:* **Filter** that matches documents in which the `title` value is `'The
  Room'`.

* **Sort** that organizes matched documents in descending order by
  rating, so if our query matches multiple documents the returned
  document will be the document with the highest rating.

* **Projection** that explicitly excludes the `_id` field from
  returned documents and explicitly includes only the `title` and
  `imdb` object (and its embedded fields).**JavaScript:**JavaScript```javascript
import { MongoClient } from "mongodb";

// Replace the uri string with your MongoDB deployment's connection string.
const uri = "<connection string uri>";

const client = new MongoClient(uri);

async function run() {
  try {

    // Get the database and collection on which to run the operation
    const database = client.db("sample_mflix");
    const movies = database.collection("movies");

    // Query for a movie that has the title 'The Room'
    const query = { title: "The Room" };

    const options = {
      // Sort matched documents in descending order by rating
      sort: { "imdb.rating": -1 },
      // Include only the `title` and `imdb` fields in the returned document
      projection: { _id: 0, title: 1, imdb: 1 },
    };

    // Execute query
    const movie = await movies.findOne(query, options);

    // Print the document returned by findOne()
    console.log(movie);
  } finally {
    await client.close();
  }
}
run().catch(console.dir);

```**TypeScript:**TypeScript```typescript
import { MongoClient } from "mongodb";

// Replace the uri string with your MongoDB deployment's connection string.
const uri = "<connection string uri>";

const client = new MongoClient(uri);

interface IMDB {
  rating: number;
  votes: number;
  id: number;
}

export interface Movie {
  title: string;
  year: number;
  released: Date;
  plot: string;
  type: "movie" | "series";
  imdb: IMDB;
}

type MovieSummary = Pick<Movie, "title" | "imdb">;

async function run(): Promise<void> {
  try {
    const database = client.db("sample_mflix");
    // Specifying a Schema is always optional, but it enables type hinting on
    // finds and inserts
    const movies = database.collection<Movie>("movies");

    const movie = await movies.findOne<MovieSummary>(
      { title: "The Room" },
      {
        sort: { rating: -1 },
        projection: { _id: 0, title: 1, imdb: 1 },
      }
    );
    console.log(movie);
  } finally {
    await client.close();
  }
}
run().catch(console.dir);

